import React, { useState, useEffect, useRef, useMemo } from 'react';

const theme = {
  colors: {
    primary: '#8b5cf6',
    background: '#0a0a0a',
    surface: '#111111',
    surfaceAlt: '#1a1a1a',
    border: '#2a2a2a',
    text: '#fafafa',
    textSecondary: '#a1a1aa',
    textMuted: '#52525b',
    blue: '#38bdf8',
    green: '#22c55e',
    negative: '#f43f5e',
    yellow: '#fbbf24',
  },
  font: "'JetBrains Mono', monospace",
};

function computeRouge1(reference, candidate) {
  const refTokens = reference.toLowerCase().split(/\s+/).filter(t => t.length > 0);
  const candTokens = candidate.toLowerCase().split(/\s+/).filter(t => t.length > 0);

  const refCounter = {};
  refTokens.forEach(w => { refCounter[w] = (refCounter[w] || 0) + 1; });

  const candCounter = {};
  candTokens.forEach(w => { candCounter[w] = (candCounter[w] || 0) + 1; });

  let overlap = 0;
  for (const w in candCounter) {
    if (refCounter[w]) {
      overlap += Math.min(refCounter[w], candCounter[w]);
    }
  }

  const precision = candTokens.length > 0 ? overlap / candTokens.length : 0;
  const recall = refTokens.length > 0 ? overlap / refTokens.length : 0;
  const f1 = (precision + recall) > 0 ? (2 * precision * recall) / (precision + recall) : 0;

  const refCopy = { ...refCounter };
  const candMatched = candTokens.map(w => {
    if (refCopy[w] && refCopy[w] > 0) {
      refCopy[w]--;
      return true;
    }
    return false;
  });

  const candCopy = { ...candCounter };
  const refMatched = refTokens.map(w => {
    if (candCopy[w] && candCopy[w] > 0) {
      candCopy[w]--;
      return true;
    }
    return false;
  });

  return { precision, recall, f1, overlap, refTokens, candTokens, refMatched, candMatched };
}

const presets = [
  { name: 'Similar', text: 'the cat is on the mat' },
  { name: 'Verbose', text: 'the big cat sat right on top of the old mat' },
  { name: 'Concise', text: 'cat sat mat' },
  { name: 'Off-topic', text: 'dogs run in the park quickly' },
  { name: 'Perfect', text: 'the cat sat on the mat' },
];

function WordPill({ word, matched, type }) {
  const matchColor = type === 'ref' ? theme.colors.green : theme.colors.blue;
  const missColor = theme.colors.negative;
  return (
    <span style={{
      display: 'inline-block',
      padding: '3px 9px',
      margin: '2px 3px',
      borderRadius: 6,
      fontSize: 13,
      fontFamily: theme.font,
      fontWeight: 600,
      background: matched ? (type === 'ref' ? 'rgba(34,197,94,0.13)' : 'rgba(56,189,248,0.13)') : 'rgba(244,63,94,0.08)',
      color: matched ? matchColor : missColor,
      border: '1px solid ' + (matched ? (type === 'ref' ? 'rgba(34,197,94,0.3)' : 'rgba(56,189,248,0.3)') : 'rgba(244,63,94,0.2)'),
      transition: 'all 0.3s ease',
    }}>
      {word}
    </span>
  );
}

function ScoreBar({ label, value, color, detail }) {
  return (
    <div style={{ marginBottom: 10 }}>
      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 4 }}>
        <span style={{ fontSize: 12, color: theme.colors.textSecondary, fontFamily: theme.font }}>{label}</span>
        <div style={{ display: 'flex', alignItems: 'center', gap: 8 }}>
          <span style={{ fontSize: 10, color: theme.colors.textMuted, fontFamily: theme.font }}>{detail}</span>
          <span style={{ fontSize: 14, fontWeight: 700, color: color, fontFamily: theme.font, minWidth: 52, textAlign: 'right' }}>
            {(value * 100).toFixed(1)}%
          </span>
        </div>
      </div>
      <div style={{ height: 8, background: theme.colors.surfaceAlt, borderRadius: 4, overflow: 'hidden' }}>
        <div style={{
          height: '100%',
          width: Math.max(0, Math.min(100, value * 100)) + '%',
          background: color,
          borderRadius: 4,
          transition: 'width 0.4s ease',
        }} />
      </div>
    </div>
  );
}

export default function App() {
  const reference = 'the cat sat on the mat';
  const [candidate, setCandidate] = useState('the cat is on the mat');
  const [playing, setPlaying] = useState(false);
  const [presetIdx, setPresetIdx] = useState(0);
  const timerRef = useRef(null);

  const result = useMemo(() => computeRouge1(reference, candidate), [candidate]);
  const { precision, recall, f1, overlap, refTokens, candTokens, refMatched, candMatched } = result;

  useEffect(() => {
    if (!playing) {
      if (timerRef.current) clearInterval(timerRef.current);
      return;
    }
    let idx = 0;
    setCandidate(presets[0].text);
    setPresetIdx(0);
    timerRef.current = setInterval(() => {
      idx++;
      if (idx >= presets.length) {
        setPlaying(false);
        if (timerRef.current) clearInterval(timerRef.current);
        return;
      }
      setCandidate(presets[idx].text);
      setPresetIdx(idx);
    }, 2000);
    return () => { if (timerRef.current) clearInterval(timerRef.current); };
  }, [playing]);

  const handleReset = () => {
    setPlaying(false);
    setCandidate('the cat is on the mat');
    setPresetIdx(0);
  };

  const getInsight = () => {
    if (candTokens.length === 0) return 'Type a candidate summary above to see how it compares to the reference.';
    if (overlap === 0) return 'No words overlap. The candidate shares nothing with the reference -- all scores are zero.';
    if (precision > 0.95 && recall > 0.95) return 'Near-perfect! Almost every word overlaps both ways. Precision and recall are both high, giving a high F1.';
    if (precision > recall + 0.15) return 'High precision, lower recall: every candidate word is relevant, but you are missing words from the reference. The summary is too short.';
    if (recall > precision + 0.15) return 'High recall, lower precision: most reference words are captured, but you added extra irrelevant words. The summary is too verbose.';
    if (f1 > 0.7) return 'Good balance! The candidate captures key content without too much extra. F1 rewards this balance.';
    if (f1 > 0.3) return 'Moderate overlap. Some key words are captured but the summary could be closer to the reference.';
    return 'Low overlap. The candidate captures very little of the reference content.';
  };

  return (
    <div style={{
      minHeight: '100vh',
      background: theme.colors.background,
      color: theme.colors.text,
      fontFamily: theme.font,
      display: 'flex',
      justifyContent: 'center',
      padding: '20px 16px',
    }}>
      <div style={{ maxWidth: 600, width: '100%' }}>
        {/* Header */}
        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 14 }}>
          <div>
            <h1 style={{ fontSize: 18, fontWeight: 700, margin: 0 }}>ROUGE-1 Score</h1>
            <p style={{ fontSize: 11, color: theme.colors.textSecondary, margin: '3px 0 0 0' }}>
              Edit the candidate and watch word overlaps change
            </p>
          </div>
          <div style={{ display: 'flex', gap: 6 }}>
            <button onClick={() => setPlaying(!playing)} style={{
              width: 32, height: 32, borderRadius: 8,
              background: playing ? theme.colors.primary : theme.colors.surface,
              border: '1px solid ' + theme.colors.border,
              color: theme.colors.text, cursor: 'pointer',
              display: 'flex', alignItems: 'center', justifyContent: 'center',
              fontSize: 12, fontFamily: theme.font,
            }}>
              {playing ? '||' : '>'}
            </button>
            <button onClick={handleReset} style={{
              width: 32, height: 32, borderRadius: 8,
              background: theme.colors.surface,
              border: '1px solid ' + theme.colors.border,
              color: theme.colors.text, cursor: 'pointer',
              fontSize: 14, fontFamily: theme.font,
            }}>
              ~
            </button>
          </div>
        </div>

        {/* Reference */}
        <div style={{ background: theme.colors.surface, borderRadius: 10, padding: 12, marginBottom: 8, border: '1px solid ' + theme.colors.border }}>
          <div style={{ fontSize: 10, color: theme.colors.textMuted, marginBottom: 6, textTransform: 'uppercase', letterSpacing: 1 }}>
            Reference ({refTokens.length} words)
          </div>
          <div style={{ display: 'flex', flexWrap: 'wrap' }}>
            {refTokens.map((w, i) => (
              <WordPill key={'r' + i} word={w} matched={refMatched[i]} type="ref" />
            ))}
          </div>
        </div>

        {/* Candidate */}
        <div style={{ background: theme.colors.surface, borderRadius: 10, padding: 12, marginBottom: 8, border: '1px solid ' + theme.colors.border }}>
          <div style={{ fontSize: 10, color: theme.colors.textMuted, marginBottom: 6, textTransform: 'uppercase', letterSpacing: 1 }}>
            Candidate ({candTokens.length} words)
          </div>
          <input
            type="text"
            value={candidate}
            onChange={(e) => { setCandidate(e.target.value); setPresetIdx(-1); }}
            style={{
              width: '100%',
              padding: '8px 10px',
              background: theme.colors.surfaceAlt,
              border: '1px solid ' + theme.colors.border,
              borderRadius: 6,
              color: theme.colors.text,
              fontFamily: theme.font,
              fontSize: 13,
              outline: 'none',
              boxSizing: 'border-box',
              marginBottom: 8,
            }}
          />
          <div style={{ display: 'flex', flexWrap: 'wrap', minHeight: 28 }}>
            {candTokens.map((w, i) => (
              <WordPill key={'c' + i} word={w} matched={candMatched[i]} type="cand" />
            ))}
          </div>
        </div>

        {/* Presets */}
        <div style={{ display: 'flex', gap: 5, marginBottom: 12, flexWrap: 'wrap' }}>
          {presets.map((p, i) => (
            <button
              key={i}
              onClick={() => { setCandidate(p.text); setPresetIdx(i); setPlaying(false); }}
              style={{
                padding: '4px 10px',
                borderRadius: 6,
                border: '1px solid ' + (presetIdx === i ? theme.colors.primary : theme.colors.border),
                background: presetIdx === i ? 'rgba(139,92,246,0.15)' : theme.colors.surface,
                color: presetIdx === i ? theme.colors.primary : theme.colors.textSecondary,
                fontFamily: theme.font,
                fontSize: 11,
                cursor: 'pointer',
                transition: 'all 0.2s ease',
              }}
            >
              {p.name}
            </button>
          ))}
        </div>

        {/* Overlap count */}
        <div style={{ textAlign: 'center', padding: '6px 0', marginBottom: 8 }}>
          <span style={{ fontSize: 26, fontWeight: 700, color: theme.colors.yellow, transition: 'all 0.3s ease' }}>{overlap}</span>
          <span style={{ fontSize: 12, color: theme.colors.textSecondary }}> overlapping unigram{overlap !== 1 ? 's' : ''}</span>
        </div>

        {/* Score Bars */}
        <div style={{ background: theme.colors.surface, borderRadius: 10, padding: 14, marginBottom: 10, border: '1px solid ' + theme.colors.border }}>
          <ScoreBar
            label="Precision"
            value={precision}
            color={theme.colors.blue}
            detail={overlap + ' / ' + candTokens.length + ' cand'}
          />
          <ScoreBar
            label="Recall"
            value={recall}
            color={theme.colors.green}
            detail={overlap + ' / ' + refTokens.length + ' ref'}
          />
          <ScoreBar
            label="F1 Score"
            value={f1}
            color={theme.colors.yellow}
            detail="2*P*R / (P+R)"
          />
        </div>

        {/* Insight */}
        <div style={{
          padding: '10px 14px',
          background: theme.colors.surface,
          borderRadius: 8,
          borderLeft: '3px solid ' + theme.colors.yellow,
          fontSize: 12,
          color: theme.colors.textSecondary,
          lineHeight: 1.6,
          marginBottom: 8,
        }}>
          <strong style={{ color: theme.colors.text }}>Insight: </strong>
          {getInsight()}
        </div>

        {/* Legend */}
        <div style={{
          padding: '8px 14px',
          background: theme.colors.surface,
          borderRadius: 8,
          fontSize: 10,
          color: theme.colors.textMuted,
          textAlign: 'center',
          lineHeight: 1.6,
        }}>
          <span style={{ color: theme.colors.green }}>Green</span>{' = matched in reference  '}
          <span style={{ color: theme.colors.blue }}>Blue</span>{' = matched in candidate  '}
          <span style={{ color: theme.colors.negative }}>Red</span>{' = no match'}
        </div>
      </div>
    </div>
  );
}
